array.string:
export PATH="$HOME/.local/bin:/usr/local/bin:/opt/homebrew/bin:$PATH";
cd /Users/tm/Projects/Claude/ResearchMan;
LOG=$HOME/Library/Logs/researchman-watchdog.log;
[ -f $LOG ] && [ $(stat -f%z $LOG) -gt 5242880 ] && mv $LOG $LOG.1;
STATE=.last-watchdog-run.txt;
AMDUE=0;
node scripts/run-if-due.mjs --state $STATE --daily-at 12 --minute 30 >> $LOG 2>&1 && AMDUE=1;
PMDUE=0;
if [ "$AMDUE" = "0" ]; then
  node scripts/run-if-due.mjs --state $STATE --daily-at 18 --minute 30 >> $LOG 2>&1 && PMDUE=1;
fi;
if [ "$AMDUE" = "0" ] && [ "$PMDUE" = "0" ]; then exit 0; fi;
DEEP="";
if [ "$PMDUE" = "1" ] && [ "$(date +%u)" = "7" ]; then DEEP="--deep"; fi;
LOCK=/tmp/researchman-git.lock; waited=0;
while ! mkdir $LOCK 2>/dev/null; do
  if [ -d $LOCK ] && [ $(( $(date +%s) - $(stat -f %m $LOCK) )) -gt 5400 ]; then
    echo "staleロック奪取: $(date)" >> $LOG; rmdir $LOCK 2>/dev/null; continue;
  fi;
  sleep 30; waited=$((waited+30));
  [ $waited -ge 1800 ] && { echo "ロック取得タイムアウト: $(date)" >> $LOG; exit 0; };
done;
trap "rmdir $LOCK 2>/dev/null" EXIT;
echo "===== Watchdog start ($([ "$AMDUE" = "1" ] && echo AM || echo PM)$([ -n "$DEEP" ] && echo " +deep")): $(date) =====" >> $LOG;
node scripts/watchdog.mjs $DEEP >> $LOG 2>&1 || echo "watchdogエラー終了: $(date)" >> $LOG;
echo "Watchdog completed: $(date)" >> $LOG
